$headers = @{ 'Authorization' = "Bearer $env:NOTION_TOKEN"; 'Notion-Version' = '2022-06-28'; 'Content-Type'='application/json' }
$updates = @(
  @{ id='32f0a0b1-97cc-811c-8700-f133f9cffac4'; next='Medir si la nueva HEARTBEAT.md mejora accion real en los proximos 3 dias.'; check='2026-04-02'; evidence='Checklist operativa ya aplicada en HEARTBEAT.md.' },
  @{ id='3300a0b1-97cc-814f-aede-dd756a5fd37a'; evidence='Dominio comprado como tradelabjournal.com.' },
