  @{ id='32f0a0b1-97cc-81fd-a5af-ca19324998c5'; evidence='Pierna A enviada por Ares al grupo Smart Project con evidencia real de entrega.' },
  @{ id='32f0a0b1-97cc-812d-be2e-ef857164a009'; evidence='Whisper configurado y operativo.' },
  @{ id='32f0a0b1-97cc-812f-9b3a-c5f430f85935'; evidence='Dominio ya adquirido y confirmado.' }
)
